namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 64;  // 256 bytes for float
static constexpr uint32_t MAX_TILE_ROWS = 128;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    MaskedCumsumCustomTilingData tiling;
    const auto &shape = context->GetInputShape(0)->GetOriginShape();
    const uint32_t totalLength = static_cast<uint32_t>(shape.GetShapeSize());

    // dim is the third input
    const int32_t *dimPtr = reinterpret_cast<const int32_t*>(
        context->GetInputTensor(2)->GetData());
    uint32_t axis = static_cast<uint32_t>(*dimPtr);
    uint32_t dimSize = static_cast<uint32_t>(shape.GetDimSize(axis));
    uint32_t numRows = totalLength / dimSize;

    // Compute tileRows from UB budget
    // For each row we need: one row of x (float) + one row of mask (uint8 converted to float) + tmp for multiplication + output + CumSum tmp buffer (approx size of 2 rows)
    // Conservative: each row uses sizeof(float)*dimSize * 5 bytes
    uint32_t bytesPerRow = dimSize * sizeof(float) * 5;
    uint32_t maxRows = (bytesPerRow == 0) ? 1 : (UB_BUDGET_BYTES / bytesPerRow);
    if (maxRows > MAX_TILE_ROWS) maxRows = MAX_TILE_ROWS;
    if (maxRows > numRows) maxRows = numRows;
    if (maxRows == 0) maxRows = 1;

    uint32_t tileRows = AlignDown(maxRows, 1u);  // no alignment needed on rows

    uint32_t blockDim = CeilDiv(numRows, tileRows);
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_dimSize(dimSize);
    tiling.set_tileRows(tileRows);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

